```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::reader reader(buffer);

    NetworkPacket packet;

    // Read packet_id
    packet.packet_id = reader.read<uint32_t>();

    // Read username using length prefix
    packet.username = reader.read_prefixed_string<uint32_t>();

    // Read score count, then use read_container to read the scores vector
    uint32_t score_count = reader.read<uint32_t>();
    packet.scores = reader.read_container<std::vector<uint32_t>>(score_count);

    // Read metadata string as null-terminated for zero-copy
    packet.metadata = reader.read_string_null_terminated();

    // Skip any remaining padding bytes
    reader.skip(reader.remaining());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::reader reader(buffer);

    PacketInfo info;

    // Use span() to get a zero-copy view of the packet_id (first 4 bytes)
    auto packet_id_span = reader.span<uint32_t>(1);
    info.packet_id = packet_id_span[0];

    // Read username using prefixed adaptor to get a string_view
    info.username = reader.read_prefixed_string_view<uint32_t>();

    // Skip the scores vector without reading its elements
    // Read count first, then skip the data
    uint32_t score_count = reader.read<uint32_t>();
    reader.skip(score_count * sizeof(uint32_t));

    return info;
}
```

