struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a Hexi span for zero-copy reading
    hexi::span hex_span(buffer.data(), buffer.size());

    // Ensure we have enough data for the header
    if (hex_span.size() < sizeof(PacketHeader)) {
        throw std::runtime_error("Buffer too small for packet header");
    }

    // Use Hexi's structured reading for zero-copy header extraction
    auto header_span = hex_span.subspan(0, sizeof(PacketHeader));

    // Convert to PacketHeader using zero-copy reinterpretation
    const PacketHeader* header_ptr = 
        reinterpret_cast<const PacketHeader*>(header_span.data());

    return *header_ptr;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Create a Hexi view for zero-copy string operations
    hexi::view hex_view(buffer.data(), buffer.size());

    // Find the null terminator using zero-copy search
    const uint8_t* data_start = hex_view.data();
    const uint8_t* null_pos = static_cast<const uint8_t*>(
        std::memchr(data_start, '\0', hex_view.size()));

    if (null_pos) {
        // Found null terminator - return view up to (but not including) the null
        return std::string_view(reinterpret_cast<const char*>(data_start),
                               null_pos - data_start);
    } else {
        // No null terminator found - return entire buffer as string view
        return std::string_view(reinterpret_cast<const char*>(data_start),
