```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a buffer_adaptor from the source buffer
    hexi::buffer_adaptor adaptor(source_buffer.data(), source_buffer.size());

    // Determine how many bytes we can actually read (don't read past the end)
    size_t actual_bytes_to_read = std::min(bytes_to_read, source_buffer.size());

    // Create destination vector and read the data
    std::vector<uint8_t> result(actual_bytes_to_read);
    adaptor.read(reinterpret_cast<char*>(result.data()), actual_bytes_to_read);

    return result;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Resize destination buffer if needed to accommodate the source data
    if (dest_buffer.size() < source_data.size()) {
        dest_buffer.resize(source_data.size());
    }

    // Create a buffer_adaptor for the destination buffer
    hexi::buffer_adaptor adaptor(dest_buffer.data(), dest_buffer.size());

    // Write the source data to the destination buffer
    adaptor.write(reinterpret_cast<const char*>(source_data.data()), source_data.size());
}
```

