Here's the complete implementation of the function using the Hexi library:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>
#include <stdexcept>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // Check if buffer has at least 1 byte for data_type
    if (buffer.empty()) {
        throw std::runtime_error("Buffer is empty");
    }

    // Preview the first byte (data_type) without advancing the read pointer
    hexi::buffer_adaptor adaptor(buffer.data(), buffer.size());
    result.data_type = adaptor.peek<uint8_t>();

    // Check available data size - need at least 5 bytes (1 for data_type + 4 for item_count)
    if (buffer.size() < 5) {
        throw std::runtime_error("Buffer too small for header");
    }

    // Read the complete data using binary_stream
    hexi::binary_stream stream(buffer.data(), buffer.size());

    // Read data_type (this will advance the pointer)
    uint8_t data_type = stream.read<uint8_t>();

    // Read item_count
    uint32_t item_count = stream.read<uint32_t>();

    // Verify the data_type matches what we previewed
    if (data_type != result.data_type) {
        throw std::runtime_error("Data type mismatch between preview and actual read");
    }

    // Calculate required size for items
    size_t item_size = (data_type == 0) ? sizeof(uint32_t) : sizeof(float);
    size_t required_size = 5 + item_count * item_size; // 1 byte + 4 bytes + items

    if (buffer.size() < required_size) {
        throw std::runtime_error("Buffer too small for expected items");
    }

    // Read items based on data_type
    if (data_type == 0) {
        // Integers
        result.int_items.reserve(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            result.int_items.push_back(stream.read<uint32_t>());
        }
    } else if (data_type == 1) {
        // Floats
        result.float_items.reserve(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            result.float_items.push_back(stream.read<float>());
        }
    } else {
        throw std::runtime_error("Invalid data type: " + std::to_string(data_type));
    }

    return result;
}
```

