```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <stdexcept>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the span
    hexi::buffer_adaptor adaptor(buffer.data(), buffer.size());

    // Check available data using buffer_adaptor methods
    if (adaptor.available() < sizeof(PacketHeader)) {
        throw std::runtime_error("Insufficient data for packet header");
    }

    // Get the read pointer using buffer_adaptor
    const uint8_t* read_ptr = adaptor.read_ptr();

    // Create a binary_stream for zero-copy operations
    hexi::binary_stream stream(read_ptr, adaptor.available());

    // Read header fields using binary_stream's zero-copy operations
    PacketHeader header;
    stream.read(header.magic);
    stream.read(header.version);
    stream.read(header.flags);

    // Advance the buffer_adaptor's read pointer to reflect the consumed data
    adaptor.advance_read_ptr(sizeof(PacketHeader));

    return header;
}
```

