#include <cstdint>
#include <iostream>
#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using namespace hexi;

    // Create a block allocator for integers with specified element count
    block_allocator<int, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Allocator capacity: " << element_count << " blocks\n\n";

    // Track allocated blocks
    std::vector<int*> allocated_blocks;

    // Phase 1: Allocate all available blocks
    std::cout << "Phase 1: Allocating all " << element_count << " blocks...\n";
    for (size_t i = 0; i < element_count; ++i) {
        int* block = allocator.allocate(1);
        *block = static_cast<int>(i); // Initialize with some value
        allocated_blocks.push_back(block);
        std::cout << "Allocated block " << i << " at address: " << block 
                  << " (value: " << *block << ")\n";
    }

    // Try to allocate one more (should fail or throw)
    std::cout << "\nTrying to allocate one more block (should fail)...\n";
    try {
        int* extra_block = allocator.allocate(1);
        std::cout << "Unexpectedly allocated extra block at: " << extra_block << "\n";
    } catch (const std::bad_alloc& e) {
        std::cout << "Expected exception: " << e.what() << "\n";
    }

    // Phase 2: Deallocate blocks in reverse order (LIFO behavior)
    std::cout << "\nPhase 2: Deallocating blocks in reverse order...\n";
    while (!allocated_blocks.empty()) {
        int* block = allocated_blocks.back();
        std::cout << "Deallocating block at: " << block << " (value: " << *block << ")\n";
        allocator.deallocate(block, 1);
        allocated_blocks.pop_back();
    }

    // Phase 3: Re-allocate blocks (should get them back in reverse order due to LIFO free list)
    std::cout << "\nPhase 3: Re-allocating blocks...\n";
    std::cout << "Due to LIFO free list management, blocks should be returned in reverse order:\n";

    for (size_t i = 0; i < element_count; ++i) {
        int* block = allocator.allocate(1);
        *block = static_cast<int>(i + 100); // Different values to distinguish
        std::cout << "Re-allocated block at: " << block << " (new value: " << *block << ")\n";
        allocated_blocks.push_back(block);
    }

    // Phase 4: Demonstrate mixed allocation pattern
    std::cout << "\nPhase 4: Mixed allocation pattern demonstration...\n";

    // Deallocate some blocks in a specific pattern
    std::cout << "Deallocating blocks at positions 2, 4, and 6...\n";
    allocator.deallocate(allocated_blocks[2], 1);
    allocator.deallocate(allocated_blocks[4], 1);
    allocator.deallocate(allocated_blocks[6], 1);

    // These blocks should now be available for allocation
    std::cout << "Allocating 3 new blocks...\n";
    for (int i = 0; i < 3; ++i) {
        int* new_block = allocator.allocate(1);
        *new_block = static_cast<int>(i + 200);
        std::cout << "New block allocated at: " << new_block << " (value: " << *new_block << ")\n";

        // The new allocations should come from the recently freed blocks
        // due to the free list's LIFO behavior (push/pop operations)
    }

    // Clean up remaining blocks
    for (size_t i = 0; i < allocated_blocks.size(); ++i) {
        if (i != 2 && i != 4 && i != 6) { // Skip already deallocated blocks
            allocator.deallocate(allocated_blocks[i], 1);
