    std::cout << "This demonstrates how the block_allocator uses push() and pop() operations\n";
    std::cout << "on its internal free list for efficient memory management:\n";
    std::cout << "- push(): adds freed blocks to the head of the free list\n";
    std::cout << "- pop(): removes and returns the head block when allocating\n";
    std::cout << "- LIFO behavior ensures recently freed blocks are reused first\n";
}

