#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Open file buffer for reading
    hexi::file_buffer file(file_path, "rb");

    // Get the actual readable size (don't read beyond file size)
    size_t file_size = file.size();
    size_t actual_bytes_to_read = (bytes_to_read > file_size) ? file_size : bytes_to_read;

    // Read data into vector
    std::vector<uint8_t> buffer(actual_bytes_to_read);
    if (actual_bytes_to_read > 0) {
        file.read(buffer.data(), actual_bytes_to_read);
    }

    return buffer;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Open file buffer for reading
    hexi::file_buffer file(file_path, "rb");

    // Save current read position
    size_t original_position = file.tell();

    // Get the actual preview size (don't read beyond file size)
    size_t file_size = file.size();
    size_t actual_bytes_to_preview = (bytes_to_preview > file_size) ? file_size : bytes_to_preview;

    // Read data into vector without advancing pointer
    std::vector<uint8_t> buffer(actual_bytes_to_preview);
    if (actual_bytes_to_preview > 0) {
        file.read(buffer.data(), actual_bytes_to_preview);

        // Reset to original position
        file.seek(original_position);
    }

    return buffer;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Open file buffer for writing (creates file if it doesn't exist)
    hexi::file_buffer file(file_path, "wb");

    // Write data to file
    if (!data.empty()) {
        file.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Open file buffer for reading
    hexi::file_buffer file(file_path, "rb");

    // Return the size of readable data
    return file.size();
}
