```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a file buffer for reading
    hexi::file_buffer file;

    // Open the file
    if (!file.open(file_path)) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Get current read position to restore later
    auto original_pos = file.tell();

    // Seek to beginning of file
    if (!file.seek(0)) {
        file.close();
        return {}; // Return empty vector if seek fails
    }

    // Read the header data
    std::vector<uint8_t> header_data(header_size);
    size_t bytes_read = file.read(header_data.data(), header_size);

    // Resize vector to actual bytes read (in case file is smaller than header_size)
    header_data.resize(bytes_read);

    // Restore original read position
    file.seek(original_pos);

    // Close the file
    file.close();

    return header_data;
}
```

