    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    std::vector<uint8_t> buffer;

    // Serialize packet_id using varint encoding
    hexi::serialize(buffer, hexi::varint(packet.packet_id));

    // Serialize tags vector using prefixed_varint adaptor
    // First encode the number of tags, then each tag string
    hexi::serialize(buffer, hexi::prefixed_varint(packet.tags.size()));
    for (const auto& tag : packet.tags) {
        hexi::serialize(buffer, hexi::prefixed_varint(tag));
    }

    // Serialize data string using prefixed_varint adaptor
    hexi::serialize(buffer, hexi::prefixed_varint(packet.data));

    return buffer;
}

