    CompactPacket packet;
    size_t offset = 0;

    // Deserialize packet_id using varint decoding
    offset = hexi::deserialize(buffer.subspan(offset), hexi::varint(packet.packet_id));

    // Deserialize tags vector size using prefixed_varint
    size_t tags_count;
    offset = hexi::deserialize(buffer.subspan(offset), hexi::prefixed_varint(tags_count));

    // Deserialize each tag string
    packet.tags.resize(tags_count);
    for (size_t i = 0; i < tags_count; ++i) {
        offset = hexi::deserialize(buffer.subspan(offset), hexi::prefixed_varint(packet.tags[i]));
    }

    // Deserialize data string using prefixed_varint
    offset = hexi::deserialize(buffer.subspan(offset), hexi::prefixed_varint(packet.data));

