```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a read adaptor for the buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    // Use read_ptr() to get pointer to current position without consuming
    const uint8_t* ptr = adaptor.read_ptr(sizeof(Header));
    if (!ptr) {
        throw std::runtime_error("Buffer too small for header");
    }

    // Use copy() to peek at header data without advancing read cursor
    Header header;
    adaptor.copy(reinterpret_cast<uint8_t*>(&header), sizeof(Header));

    // Verify the pointer position hasn't changed
    const uint8_t* current_ptr = adaptor.read_ptr(0);
    if (current_ptr != ptr) {
        throw std::runtime_error("Read cursor was unexpectedly advanced");
    }

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    hexi::pmc::buffer_read_adaptor adaptor(buffer);
    std::vector<uint8_t> result;

    // Use copy() to peek at first byte
    uint8_t first_byte;
    if (adaptor.copy(&first_byte, 1) != 1) {
        return result; // Empty vector if buffer is empty
    }

    // Condition: if first byte is non-zero, read more data
    if (first_byte != 0) {
        // Determine how much data to read based on the peeked value
        size_t data_size;
        if (first_byte < 0x80) {
            data_size = first_byte; // Small payload
        } else {
            data_size = 256; // Large payload
        }

        // Ensure we don't read beyond buffer size
        data_size = std::min(data_size, buffer.size());

        // Use read() to consume the data including the first byte we peeked at
        result.resize(data_size);
        adaptor.read(result.data(), data_size);
    }

    return result;
}
